        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        if (blockIdx >= batchSize_) return;

        uint32_t rowBase = blockIdx * rowSize_;
        float carry = 0.0f;

        uint32_t remaining = rowSize_;
        uint32_t tileOff = 0;
